module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
    reg [1:0] mul_en_out_reg;
    reg [7:0] mul_a_reg;
    reg [7:0] mul_b_reg;
    reg [8:0] sum [7:0];
    reg [15:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_en_out_reg <= 2'b00;
        end else if (mul_en_in) begin
            mul_en_out_reg <= 2'b01;
        end else if (mul_en_out) begin
            mul_en_out_reg <= 2'b10;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_a_reg <= 8'h00;
            mul_b_reg <= 8'h00;
        end else if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end

    wire [7:0] temp [7:0];
    assign temp[0] = mul_a_reg & {8{mul_b_reg[0]}};
    assign temp[1] = mul_a_reg & {8{mul_b_reg[1]}};
    assign temp[2] = mul_a_reg & {8{mul_b_reg[2]}};
    assign temp[3] = mul_a_reg & {8{mul_b_reg[3]}};
    assign temp[4] = mul_a_reg & {8{mul_b_reg[4]}};
    assign temp[5] = mul_a_reg & {8{mul_b_reg[5]}};
    assign temp[6] = mul_a_reg & {8{mul_b_reg[6]}};
    assign temp[7] = mul_a_reg & {8{mul_b_reg[7]}};

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum[0] <= 9'd0;
            sum[1] <= 9'd0;
            sum[2] <= 9'd0;
            sum[3] <= 9'd0;
            sum[4] <= 9'd0;
            sum[5] <= 9'd0;
            sum[6] <= 9'd0;
            sum[7] <= 9'd0;
        end else begin
            sum[0] <= temp[0];
            sum[1] <= sum[0] + temp[1];
            sum[2] <= sum[1] + temp[2];
            sum[3] <= sum[2] + temp[3];
            sum[4] <= sum[3] + temp[4];
            sum[5] <= sum[4] + temp[5];
            sum[6] <= sum[5] + temp[6];
            sum[7] <= sum[6] + temp[7];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out_reg <= 16'h0000;
        end else begin
            mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5] + sum[6] + sum[7];
        end
    end

    assign mul_out = mul_en_out ? mul_out_reg : 16'h0000;
endmodule
